int main() {
    // Initialize the SSL library
    SSL_library_init();
    SSL_load_error_strings();
    OpenSSL_add_ssl_algorithms();

    // Create an SSL context and configure it
    const SSL_METHOD *method = TLS_server_method();
    SSL_CTX *ctx = SSL_CTX_new(method);

    // Load your server certificate and private key, configure context
    SSL_CTX_use_certificate_file(ctx, "server.crt", SSL_FILETYPE_PEM);
    SSL_CTX_use_PrivateKey_file(ctx, "server.key", SSL_FILETYPE_PEM);

    // Assume listen_sock is an already created and configured socket
    int listen_sock; // Should already be bound to the correct port and listening

    // Set up epoll to manage the connections
    int epoll_fd = epoll_create1(0);
    struct epoll_event ev, events[10];

    // Accept a new connection
    int client_sock = accept(listen_sock, NULL, NULL);
    if (client_sock < 0) {
