        exit(EXIT_FAILURE);
    }

    // Make the client socket non-blocking
    set_non_blocking(client_sock);

    // Register the client socket with epoll
    ev.events = EPOLLIN | EPOLLOUT | EPOLLET; // Edge-triggered monitoring
    ev.data.fd = client_sock;
    if (epoll_ctl(epoll_fd, EPOLL_CTL_ADD, client_sock, &ev) != 0) {
        perror("epoll_ctl");
        exit(EXIT_FAILURE);
    }

    // Create an SSL object, attach the client socket file descriptor
    SSL *ssl = SSL_new(ctx);
    SSL_set_fd(ssl, client_sock);

    // Create memory BIOs to which the SSL object will read/write
    BIO *rbio = BIO_new(BIO_s_mem());
    BIO *wbio = BIO_new(BIO_s_mem());
    SSL_set_bio(ssl, rbio, wbio);  // SSL no longer owns the socket directly

    int handshake_done = 0;
    while (!handshake_done) {
